// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Check column header', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Check column header', async function() {
    await driver.get("http://localhost:4200/admin-user/list-user");
    await driver.manage().window().setRect({ width: 1936, height: 1056 });
    await driver.findElement(By.id("create_template_form")).click();
    await driver.findElement(By.css(".main_button > span")).click();
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)")).click();
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)")).getText() == "氏名");
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(3)")).click();
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(3)")).getText() == "会社");
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(4)")).click();
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(4)")).getText() == "部名");
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(5)")).click();
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(5)")).getText() == "課名");
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(6)")).click();
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(6)")).getText() == "等級");
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(7)")).click();
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(7)")).getText() == "メール");
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(8)")).click();
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(8)")).getText() == "ロール");
  });
});
